import React, { useState, useEffect } from 'react';
import axios from 'axios';

function AdminDashboard() {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchRequests();
  }, []);

  const fetchRequests = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
      setLoading(false);
    } catch (err) {
      console.error("Error fetching data:", err);
      setLoading(false);
    }
  };

  // Generic Update Function
  const handleUpdate = async (id, updatedData) => {
    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, updatedData);
      fetchRequests(); // Refresh Data
    } catch (err) {
      alert("Error updating project details.");
    }
  };

  // Mark as Full Paid Logic (Updates status to 'Paid')
  const markAsFullPaid = async (id, totalAmount) => {
    if (window.confirm("Are you sure this project is fully paid?")) {
      handleUpdate(id, { 
        advancePaid: totalAmount, 
        paymentStatus: 'Paid' 
      });
    }
  };

  if (loading) return <div className="text-center py-5">Loading Admin Panel...</div>;

  return (
    <div className="container py-5">
      <h2 className="fw-bold mb-1">Admin <span className="text-primary">Control Panel</span></h2>
      <p className="text-muted mb-5">Manage project progress and handle payments manually.</p>

      <div className="row g-4">
        {requests.map((project) => {
          const remaining = project.totalBudget - project.advancePaid;

          return (
            <div key={project._id} className="col-12">
              <div className="card shadow-sm border-0 rounded-4 p-4 mb-2">
                <div className="row align-items-center">
                  
                  {/* 1. Client Details */}
                  <div className="col-md-3">
                    <h5 className="fw-bold mb-0 text-capitalize">{project.fullName}</h5>
                    <small className="text-primary fw-bold text-uppercase d-block mb-1">{project.serviceType}</small>
                    <small className="text-muted d-block">{project.email}</small>
                  </div>

                  {/* 2. Progress Slider Section */}
                  <div className="col-md-3 px-4">
                    <div className="d-flex justify-content-between mb-1">
                      <small className="fw-bold text-muted">Progress</small>
                      <small className="fw-bold text-primary">{project.progress}%</small>
                    </div>
                    <div className="progress rounded-pill mb-2" style={{ height: '10px' }}>
                      <div className="progress-bar bg-primary" style={{ width: `${project.progress}%` }}></div>
                    </div>
                    <input 
                      type="range" className="form-range" min="0" max="100" 
                      value={project.progress} 
                      onChange={(e) => handleUpdate(project._id, { progress: e.target.value })}
                    />
                  </div>

                  {/* 3. Payment Section (Sir's Logic: Based on Payment Status) */}
                  <div className="col-md-3 text-center border-start border-end">
                    {project.paymentStatus === 'Paid' ? (
                      <div className="py-2">
                        <span className="badge bg-success-light text-success p-2 px-3 rounded-pill fw-bold">
                          ✅ FULLY PAID
                        </span>
                        <div className="small mt-1 text-muted">Total Received: ₹{project.totalBudget}</div>
                      </div>
                    ) : (
                      <div>
                        <small className="text-muted d-block">Remaining Balance</small>
                        <h4 className="text-danger fw-bold mb-0">₹{remaining}</h4>
                        <div className="d-flex justify-content-center align-items-center gap-1">
                          <small className="text-muted">Total: ₹{project.totalBudget}</small>
                          {/* Edit Budget Button */}
                          <button 
                            className="btn btn-sm p-0 text-primary" 
                            onClick={() => {
                              const newBudget = prompt("Enter Total Budget:", project.totalBudget);
                              if(newBudget) handleUpdate(project._id, { totalBudget: newBudget });
                            }}
                          >
                            <i className="fas fa-edit ms-1" style={{fontSize: '10px'}}></i>
                          </button>
                        </div>
                      </div>
                    )}
                  </div>

                  {/* 4. Actions Section */}
                  <div className="col-md-3 text-end">
                    {project.paymentStatus !== 'Paid' ? (
                      <button 
                        className="btn btn-outline-success btn-sm px-4 rounded-pill fw-bold shadow-sm"
                        onClick={() => markAsFullPaid(project._id, project.totalBudget)}
                      >
                        Mark Full Paid
                      </button>
                    ) : (
                      <button className="btn btn-light btn-sm text-muted disabled rounded-pill border">
                        Settled
                      </button>
                    )}
                    <button 
                      className="btn btn-link text-danger ms-2"
                      onClick={async () => {
                         if(window.confirm("Delete this record?")) {
                           await axios.delete(`http://localhost:5000/api/delete-request/${project._id}`);
                           fetchRequests();
                         }
                      }}
                    >
                      <i className="fas fa-trash"></i>
                    </button>
                  </div>

                </div>
              </div>
            </div>
          );
        })}
      </div>

      {requests.length === 0 && <div className="text-center py-5 text-muted">No records found.</div>}

      <style>{`
        .bg-success-light { background-color: #e8f5e9; }
        .form-range::-webkit-slider-thumb { background: #0d6efd; }
      `}</style>
    </div>
  );
}

export default AdminDashboard;
